import React, { useContext } from "react";
import { GeneralContext } from "./GeneralContext"; //
import BuyActionWindow from "./BuyActionWindow"; //
import WatchList from "./WatchList";
import { Routes, Route } from "react-router-dom";
// Import your other views like Summary, Holdings, etc.

const Dashboard = () => {
  const { isBuyWindowOpen, selectedStockUID } = useContext(GeneralContext); //

  return (
    <div className="dashboard-container">
      <WatchList /> {/* This fills the left sidebar area */}
      <div className="content">
        <Routes>{/* Add your internal dashboard routes here */}</Routes>
      </div>
      {/* This renders the popup when triggered */}
      {isBuyWindowOpen && <BuyActionWindow uid={selectedStockUID} />}
    </div>
  );
};

export default Dashboard;
